import { expect, test, describe } from "vitest";
import { ChromaticBuleSieve } from "../chromatic-bule-sieve";

describe("Chromatic Bule Sieve — The Modulo-9 Lens", () => {
  test("deblurValue unfolds 9 shadows and selects the resonant one", () => {
    const blurred = 0.5;
    const carrier = 0.51; // A slightly higher neighbor
    
    const resolved = ChromaticBuleSieve.deblurValue(blurred, carrier);
    
    // The resolved value should be "stretched" toward the carrier 
    // but grounded in the Enneon manifold.
    expect(resolved).toBeGreaterThanOrEqual(0.5);
    expect(resolved).toBeLessThan(0.6);
  });

  test("sieveImage processes a full plane", () => {
    const width = 4;
    const height = 4;
    const plane = new Float32Array(width * height).fill(0.5);
    // Add a "blur" (a step)
    plane[5] = 0.6;
    
    const sieved = ChromaticBuleSieve.sieveImage(plane, width, height);
    
    expect(sieved).toHaveLength(16);
    expect(sieved[5]).not.toBe(0.5);
  });
});
